module top_module(
    input [7:0] A,
    input [7:0] B,
    input add,
    input sub,
    output [7:0] Z
);reg [7:0] obf_temp;

    always @(*) begin
        if (add) begin
            obf_temp = A + B;
        end
        else if (sub) begin
            obf_temp = A - B;
        end
        else begin
            obf_temp = 8'b0;
        end
    end

    assign Z = obf_temp;

endmodule
